import{_ as a,o as r,c as d,ag as e}from"./chunks/framework.DEqXEGcv.js";const b=JSON.parse('{"title":"备份与恢复","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/backup.md","filePath":"zh/docs/guide/backup.md"}'),o={name:"zh/docs/guide/backup.md"};function l(i,t,n,s,h,c){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="备份与恢复" tabindex="-1">备份与恢复 <a class="header-anchor" href="#备份与恢复" aria-label="Permalink to &quot;备份与恢复&quot;">​</a></h1><p>RDE 提供系统配置和用户数据的备份、还原、迁移功能，支持云服务器和 NAS 私有部署场景。</p><h2 id="系统配置备份" tabindex="-1">系统配置备份 <a class="header-anchor" href="#系统配置备份" aria-label="Permalink to &quot;系统配置备份&quot;">​</a></h2><table tabindex="0"><thead><tr><th>备份项</th><th>说明</th></tr></thead><tbody><tr><td>RDE 应用配置</td><td>所有模块的设置、偏好</td></tr><tr><td>用户账户</td><td>用户信息、权限、SSH 密钥</td></tr><tr><td>Docker 容器配置</td><td>docker-compose.yml、环境变量（不含镜像）</td></tr><tr><td>网络配置</td><td>DDNS、反向代理、端口映射规则</td></tr><tr><td>计划任务</td><td>定时任务、自动化脚本</td></tr><tr><td>Samba 共享配置</td><td>共享目录、访问权限</td></tr></tbody></table><h2 id="用户数据备份" tabindex="-1">用户数据备份 <a class="header-anchor" href="#用户数据备份" aria-label="Permalink to &quot;用户数据备份&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>策略</th></tr></thead><tbody><tr><td>文件/文档</td><td>全量 + 增量备份</td></tr><tr><td>照片库</td><td>含元数据、相册结构</td></tr><tr><td>数据库</td><td>SQLite 导出</td></tr><tr><td>应用数据目录</td><td>按应用选择性备份</td></tr></tbody></table><h2 id="备份目标" tabindex="-1">备份目标 <a class="header-anchor" href="#备份目标" aria-label="Permalink to &quot;备份目标&quot;">​</a></h2><p>支持多种备份目标：</p><ul><li><strong>本地磁盘</strong>：备份到本地其他分区或外置硬盘</li><li><strong>WebDAV</strong>：坚果云、ownCloud 等</li><li><strong>S3 兼容</strong>：AWS S3、MinIO、腾讯云 COS</li><li><strong>SFTP</strong>：通过 SSH 协议备份到远程服务器</li><li><strong>Rclone</strong>：支持 40+ 云存储服务</li></ul><h2 id="备份策略" tabindex="-1">备份策略 <a class="header-anchor" href="#备份策略" aria-label="Permalink to &quot;备份策略&quot;">​</a></h2><ul><li><strong>手动备份</strong>：随时手动触发</li><li><strong>定时备份</strong>：设置 cron 计划</li><li><strong>增量备份</strong>：仅备份变更文件，节省空间</li><li><strong>备份保留策略</strong>：自动清理过期备份</li></ul><h2 id="恢复" tabindex="-1">恢复 <a class="header-anchor" href="#恢复" aria-label="Permalink to &quot;恢复&quot;">​</a></h2><ul><li>从备份文件恢复系统配置</li><li>选择性恢复特定模块的数据</li><li>跨设备迁移</li></ul><div class="tip custom-block"><p class="custom-block-title">云备份</p><p>会员用户还可使用 <a href="/zh/docs/guide/cloud-backup.html">云备份</a> 服务，自动备份到云端。</p></div>',14)])])}const p=a(o,[["render",l]]);export{b as __pageData,p as default};
